// runForecast computes the weighted pipeline forecast from the local store.
// weighted = SUM(monetary_value * win_probability / 100), open = SUM(monetary_value).
// It is SELECT-only and safe to call against a read-only handle.
func runForecast(ctx context.Context, db *sql.DB, opts forecastOpts) ([]forecastRow, error) {
	status := opts.Status
	if status == "" {
		status = "Open"
	}
	by := opts.By
	if by == "" {
		by = "stage"
	}

	var groupExpr string
	switch by {
	case "assignee":
		groupExpr = "json_extract(data,'$.assignee_id')"
	case "close-month":
		// close_date arrives in several shapes depending on Copper account /
		// API version: MM/DD/YYYY text (observed), a Unix-timestamp string, or
		// ISO YYYY-MM-DD. Normalize each to a YYYY-MM bucket; substr(1,7) alone
		// would mis-bucket all but the ISO case.
		groupExpr = `CASE
			WHEN close_date GLOB '[0-9][0-9]/[0-9][0-9]/[0-9][0-9][0-9][0-9]'
				THEN substr(close_date,7,4) || '-' || substr(close_date,1,2)
			WHEN close_date GLOB '[0-9]*' AND length(close_date) >= 10 AND instr(close_date,'-') = 0 AND instr(close_date,'/') = 0
				THEN strftime('%Y-%m', datetime(CAST(close_date AS INTEGER), 'unixepoch'))
			WHEN length(close_date) >= 7 AND substr(close_date,5,1) = '-'
				THEN substr(close_date,1,7)
			ELSE close_date
		END`
	default: // stage
		groupExpr = "pipeline_stage_id"
	}

	query := fmt.Sprintf(`
		SELECT
			%s AS grp,
			COALESCE(SUM(monetary_value), 0) AS open_value,
			COALESCE(SUM(monetary_value * COALESCE(win_probability, 0) / 100.0), 0) AS weighted_value,
			COUNT(*) AS cnt
		FROM opportunities
		WHERE status = ?`, groupExpr)
	queryArgs := []any{status}
	if opts.Pipeline != "" {
		query += " AND pipeline_id = ?"
		queryArgs = append(queryArgs, opts.Pipeline)
	}
	query += " GROUP BY grp ORDER BY weighted_value DESC"

	rows, err := db.QueryContext(ctx, query, queryArgs...)
	if err != nil {
		return nil, fmt.Errorf("querying opportunities: %w", err)
	}
	defer rows.Close()

	var out []forecastRow
	for rows.Next() {
		var grp sql.NullString
		var openVal, weightedVal sql.NullFloat64
		var cnt int
		if err := rows.Scan(&grp, &openVal, &weightedVal, &cnt); err != nil {
			return nil, fmt.Errorf("scanning forecast row: %w", err)
		}
		label := grp.String
		if !grp.Valid || label == "" {
			label = "(none)"
		}
		out = append(out, forecastRow{
			Group:         label,
			OpenValue:     openVal.Float64,
			WeightedValue: weightedVal.Float64,
			Count:         cnt,
		})
	}
	if err := rows.Err(); err != nil {
		return nil, err
	}
	return out, nil
}

func renderForecast(w io.Writer, rows []forecastRow, by string, flags *rootFlags) error {
	if flags.asJSON || flags.agent {
		enc := json.NewEncoder(w)
		enc.SetIndent("", "  ")
		if rows == nil {
			rows = []forecastRow{}
		}
		return enc.Encode(rows)
	}
	fmt.Fprintf(w, "%s\topen_value\tweighted_value\tcount\n", by)
	fmt.Fprintln(w, "-----\t----------\t--------------\t-----")
	var totOpen, totWeighted float64
	var totCount int
	for _, r := range rows {
		fmt.Fprintf(w, "%s\t%.2f\t%.2f\t%d\n", r.Group, r.OpenValue, r.WeightedValue, r.Count)
		totOpen += r.OpenValue
		totWeighted += r.WeightedValue
		totCount += r.Count
	}
	fmt.Fprintf(w, "TOTAL\t%.2f\t%.2f\t%d\n", totOpen, totWeighted, totCount)
	return nil
}
